<template>
  <div class="local-material">
    <el-row v-if="categoryList && categoryList.length > 0" :gutter="10" class="main-content-row">
      <el-col :span="6" class="sidebar-col">
        <!-- 左侧分类导航 -->
        <div class="sidebar">
          <el-menu :default-active="currentCategory" background-color="#252525" text-color="#fff" active-text-color="#ffd04b" @select="handleSelect">
            <template v-for="item in categoryList">
              <el-menu-item
                :key="item.id"
                :index="item.id"
                :class="{
                  'menu-item-active': item.id === currentCategory
                }"
              >
                <template slot="title">
                  <span>{{ item.nameCn }}</span>
                </template>
              </el-menu-item>
            </template>
          </el-menu>
        </div>
      </el-col>

      <!-- 右侧素材展示区（3列网格） -->
      <el-col :span="18" class="content-col">
        <div class="content">
          <div class="content-image" v-for="item in materialAllList" :key="item.id">
            <img :src="item.thumbnail" @click="handleDownload(item)" style="width: 100%; height: 100%; object-fit: contain" />
          </div>
        </div>
      </el-col>
    </el-row>
    <el-image v-else :src="materialImg" style="margin-top: 5px; width: 100%; height: 100%; contain: conver" />
  </div>
</template>

<script>
import { getSettingInfo } from '@/api/main';
import { getCommonLocalFolderList, getCommonLocalFileList, openLocalFile } from '@/utils/cepio';

export default {
  name: 'LocalMaterial',
  props: {
    localMaterialImg: {
      type: String,
      default: ''
    }
  },
  data() {
    return {
      materialAllList: [],
      categoryList: [],
      currentCategory: '-1', // 默认选中收藏
      materialImg: null
    };
  },
  created() {
    this.getSettingInfos();
  },
  methods: {
    async getSettingInfos() {
      try {
        const response = await getSettingInfo();
        const localMaterialPath = (response.data && response.data.localMaterialPath) || null;
        if (localMaterialPath) {
          this.getCategories(localMaterialPath);
        } else {
          this.materialImg = this.localMaterialImg;
        }
      } catch (error) {
        console.error('获取设置信息失败:', error);
      }
    },
    async getCategories(localFolderAddress) {
      try {
        const response = await getCommonLocalFolderList(localFolderAddress);
        this.categoryList = response || [];
        if (this.categoryList.length > 0) {
          this.handleSelect(this.categoryList[0].id); // 默认选中第一个分类
        }
      } catch (error) {
        console.error('获取分类列表失败:', error);
      }
    },
    handleSelect(key, keyPath) {
      this.currentCategory = key;
      this.getMaterials(key);
    },
    async getMaterials(localFolderAddress) {
      try {
        const response = await getCommonLocalFileList(localFolderAddress);
        this.materialAllList = response || [];
      } catch (error) {
        console.error('获取素材列表失败:', error);
        this.materialAllList = [];
      }
    },
    async handleDownload(item) {
      try {
        await openLocalFile('localFile', item.thumbnail);
      } catch (error) {
        console.error('下载或打开失败:', error);
        this.$message.error('下载打开失败');
      }
    },
    refreshLocalMaterial() {
      // 刷新本地素材列表
      this.getSettingInfos();
    }
  }
};
</script>

